let pressureRaw = msg.values[1];
let gpmFlow = msg.values[2];
let chemicalDose = msg.values[3];
let vfdSpeed = msg.values[4];
let requiredSystemPsi = msg.values[5];
let pumpHeadPsi = msg.values[6];

msg.payload = {
    level: tankRaw / 10,
    pressurePsi: pressureRaw / 10,
    gpmFlow: gpmFlow,
    chemicalDose: Number((chemicalDose / 24).toFixed(3)),
    vfdSpeed: vfdSpeed,
    requiredSystemPsi: requiredSystemPsi,
    pumpHeadPsi: pumpHeadPsi ,

}
return msg;

let pumpCommandOn = !!msg.payload[0]
let pumpRunning = !!msg.payload[1];
let pumpFault = !!msg.payload[2];;
let chlrInjPump = !!msg.payload[3]
let lowPsiAlarm = !!msg.payload[15];

msg.payload = {
    pumpCommandOn: pumpCommandOn,
    pumpRunning: pumpRunning,
    pumpFault: pumpFault,
    lowPsiAlarm: lowPsiAlarm,
    chlrInjPump: chlrInjPump
}
return msg;

// Guard: wait until Join has both parts
if (!msg.payload || !msg.payload.hr || !msg.payload.coils) {
    return null;
}

const hr = msg.payload.hr;
const coils = msg.payload.coils;

msg.payload = {
    level: hr.level,
    pressurePsi: hr.pressurePsi,
    gpmFlow: hr.gpmFlow,
    chemicalDose: hr.chemicalDose,
    vfdSpeed: hr.vfdSpeed,
    requiredSystemPsi: hr.requiredSystemPsi,
    pumpHeadPsi: hr.pumpHeadPsi,

    pumpCommandOn: !!coils.pumpCommandOn,
    pumpRunning: !!coils.pumpRunning,
    pumpFault: !!coils.pumpFault,
    chlrInjPump: !!coils.chlrInjPump,
    lowPsiAlarm: !!coils.lowPsiAlarm
};

return msg;

format:
/* ============================
   CYBER THEME (CLEAN + SIMPLE)
   ============================ */

:root{
  --bg:#020403;
  --card:radial-gradient(120% 140% at 20% 0%, #07110a 0%, #040906 55%, #020403 100%);
  --line:rgba(0,255,120,.18);
}

/* Page bg */
html,body,.v-application,.ff-page{
  background:var(--bg)!important;
  color:#fff!important;
}

/* Top bar */
header,.v-app-bar,.v-toolbar,.v-toolbar__content,.ff-appbar,.ff-header,.ff-toolbar,
.bg-white,.bg-background,.v-theme--light .v-app-bar,.v-theme--light .v-toolbar{
  background:var(--card)!important;
  color:#fff!important;
  border-bottom:1px solid var(--line)!important;
  box-shadow:0 4px 14px rgba(0,0,0,.55)!important;
}
header *,.v-app-bar *,.v-toolbar *,.ff-appbar *,.ff-header *{
  color:#fff!important;
}
.v-app-bar .v-icon,.v-toolbar .v-icon,header .v-icon{
  color:#fff!important;
  fill:#fff!important;
}

/* Cards / groups */
.ff-group,.v-card,.v-sheet,.v-surface{
  background:var(--card)!important;
  color:#fff!important;
  border:1px solid var(--line)!important;
  box-shadow:0 4px 14px rgba(0,0,0,.55)!important;
}

/* Widgets */
.ff-widget{
  background:transparent!important;
  color:#fff!important;
}

/* Inputs */
.v-field,.v-input,.v-field__input,input,textarea,select{
  color:#fff!important;
  caret-color:#fff!important;
}
.v-field__overlay,.v-field__outline,.v-field__field{
  background:rgba(0,0,0,.45)!important;
  border-radius:12px!important;
}
.v-field__outline{
  border:1px solid var(--line)!important;
}
.v-label,.v-field-label{
  color:rgba(255,255,255,.75)!important;
  letter-spacing:.10em;
}

/* Global white text/icons */
*{color:#fff;}
[class*="text-"]{color:#fff!important;opacity:1!important;}
.v-icon,svg{color:#fff!important;fill:#fff!important;}

/* Charts */
svg path,svg polyline,svg line{stroke:#fff!important;}
svg .grid line{stroke:rgba(255,255,255,.25)!important;}

/* Alarm banner */
.alarm-banner,.alarm-banner .v-card,.alarm-banner .v-sheet,.alarm-banner .v-surface{
  background:var(--card)!important;
  border:none!important;
  outline:none!important;
  box-shadow:none!important;
}
.alarm-banner,.alarm-banner *,.alarm-banner .v-icon{
  color:#fff!important;
  fill:#fff!important;
  text-shadow:0 0 4px rgba(0,0,0,.6)!important;
}

/* Pump icon size */
.pump-icon .v-icon{font-size:80px!important;}

/* ================================
   CLICK FIX
   ================================ */
.ff-widget,.ff-widget *{pointer-events:auto!important;}
.v-overlay,.v-overlay__scrim,.v-dialog__scrim,
.v-menu__content,.v-tooltip__content{pointer-events:none!important;}
button,input,textarea,select,a{pointer-events:auto!important;}
.ff-page::before,.ff-page::after{pointer-events:none!important;}

/* =========================================
   FAULT RESET BUTTON
   ========================================= */

.faultReset{
  position:relative!important;
  display:inline-flex!important;
  align-items:center!important;
  justify-content:center!important;
  padding:10px 12px!important;
  min-height:36px!important;

  border-radius:12px!important;
  font-family:"Courier New", monospace!important;
  letter-spacing:0.12em!important;
  font-weight:900!important;

  background:var(--card)!important;
  color:#b6ffb6!important;

  border:1px solid rgba(0,255,120,0.18)!important;
  box-shadow:
    0 3px 10px rgba(0,0,0,0.55),
    inset 0 0 0 1px rgba(0,255,120,0.10)!important;

  text-shadow:0 0 5px rgba(0,255,120,0.25)!important;
  transition:filter .15s ease,transform .08s ease!important;
  cursor:pointer!important;
  user-select:none!important;
}

.faultReset:hover{
  filter:brightness(1.08)!important;
  box-shadow:0 3px 12px rgba(0,0,0,0.60)!important;
}

.faultReset:active{transform:scale(.97)!important;}

/* Disabled */
.faultReset:disabled{
  opacity:.55!important;
  background:rgba(255,255,255,.06)!important;
  border-color:rgba(255,255,255,.12)!important;
  box-shadow:inset 0 0 18px rgba(0,0,0,.85)!important;
  text-shadow:none!important;
  filter:none!important;
}

/* ================================
   ACTIVE FAULT – TRUE PUMP OFF GREY
   ================================ */
.faultReset.armed,
.faultReset.active,
.faultReset.fault{
  background:#555!important;
  background-image:none!important;
  filter:none!important;
  text-shadow:none!important;
  border:1px solid #444!important;
  color:#fff!important;
  box-shadow:inset 0 2px 6px rgba(0,0,0,.85)!important;
}

/* No brighten on hover when fault active */
.faultReset.armed:hover,
.faultReset.active:hover,
.faultReset.fault:hover{
  background:#555!important;
  filter:none!important;
  box-shadow:inset 0 2px 6px rgba(0,0,0,.85)!important;
}

/* CRT scanlines (normal only) */
.faultReset::after{
  content:"";
  position:absolute;
  inset:0;
  pointer-events:none;
  border-radius:12px;
  background:repeating-linear-gradient(
    to bottom,
    rgba(0,0,0,0)0px,
    rgba(0,0,0,0)2px,
    rgba(0,0,0,0.15)3px
  );
  opacity:.25;
}

/* Remove overlays when fault active */
.faultReset.armed::after,
.faultReset.active::after,
.faultReset.fault::after{
  display:none!important;
}

